// vector.
// ---------------------------------------------------------------------------
const DANGEROUS_OPERATORS = new Set([
  '$where',       // executes arbitrary JS on the server
  '$accumulator', // executes arbitrary JS (aggregation)
  '$function',    // executes arbitrary JS (aggregation)
  '$expr',        // can be abused to leak data across collections
  '$merge',       // writes to other collections
  '$out',         // writes to other collections
]);

// Fields that must never be returned regardless of what the caller asks for.
const FORBIDDEN_PROJECTION_FIELDS = new Set([
  'password',
  'passwordHash',
  'secret',
  'token',
  'refreshToken',
  'ssn',
]);

// Collections that may never be queried through this generic endpoint.
const FORBIDDEN_COLLECTIONS = new Set([
  'system.profile',
  'system.users',
  'system.roles',
]);

// ---------------------------------------------------------------------------
// Sanitisation helpers
// ---------------------------------------------------------------------------

/**
 * Recursively walk an object and throw if any key is a dangerous operator.
 * Also prevents prototype-pollution keys.
 */
function sanitizeFilter(obj) {
  if (obj === null || obj === undefined) return {};
  if (typeof obj !== 'object') {
    throw new Error('Filter must be an object');
  }
  if (Array.isArray(obj)) {
    obj.forEach(item => {
      if (item && typeof item === 'object') sanitizeFilter(item);
    });
    return obj;
  }

  for (const key of Object.keys(obj)) {
    // Block prototype-pollution vectors
    if (key === '__proto__' || key === 'constructor' || key === 'prototype') {
      throw new Error(`Illegal key in filter: ${key}`);
    }

    if (DANGEROUS_OPERATORS.has(key)) {
      throw new Error(`Operator "${key}" is not allowed for security reasons`);
    }

    const value = obj[key];

    // If someone passes a $regex, make sure it's a string (not an object
    // with flags that could cause ReDoS) and limit length.
    if (key === '$regex') {
      if (typeof value !== 'string' || value.length > 500) {
        throw new Error('$regex value must be a string of at most 500 characters');
      }
    }

    if (value && typeof value === 'object') {
      sanitizeFilter(value);
    }
  }

  return obj;
}

/**
 * Ensure the projection never exposes forbidden fields.
 */
function sanitizeProjection(proj) {
  if (proj === null || proj === undefined) return {};
  if (typeof proj !== 'object' || Array.isArray(proj)) {
    throw new Error('Projection must be a plain object');
  }

  const cleaned = { ...proj };

  // Always exclude forbidden fields (set to 0).
  for (const field of FORBIDDEN_PROJECTION_FIELDS) {
    // If the caller explicitly asked for this field (value 1), remove it.
    if (cleaned[field] && cleaned[field] !== 0) {
      delete cleaned[field];
    }
    cleaned[field] = 0;
  }

  return cleaned;
}

/**
 * Sort must be a plain object whose values are 1, -1, or the string
 * equivalents.
 */
function sanitizeSort(sort) {
  if (sort === null || sort === undefined) return {};
  if (typeof sort !== 'object' || Array.isArray(sort)) {
    throw new Error('Sort must be a plain object');
  }

  const cleaned = {};
  for (const [key, value] of Object.entries(sort)) {
    if (key === '__proto__' || key === 'constructor' || key === 'prototype') {
      throw new Error(`Illegal key in sort: ${key}`);
    }
    const numVal = Number(value);
    if (numVal !== 1 && numVal !== -1) {
      throw new Error(`Sort value for "${key}" must be 1 or -1`);
    }
    cleaned[key] = numVal;
  }

  return cleaned;
}

