/**
 * queryBuilder – builds and executes a MongoDB find() with the supplied
 * filter, projection, sort, and pagination parameters.
 *
 * @param {string}  collectionName  Target collection.
 * @param {object}  filter          MongoDB query filter (sanitised).
 * @param {object}  projection      Field projection (sanitised).
 * @param {object}  sort            Sort specification (sanitised).
 * @param {number}  [limit=50]      Maximum documents to return (capped at 500).
 * @param {number}  [skip=0]        Number of documents to skip.
 * @returns {Promise<{data: Array, total: number, limit: number, skip: number}>}
 */
async function queryBuilder(
  collectionName,
  filter = {},
  projection = {},
  sort = {},
  limit = 50,
  skip = 0
) {
  // --- Collection guard ---
  if (!collectionName || typeof collectionName !== 'string') {
    throw new Error('A valid collection name is required');
  }
  if (FORBIDDEN_COLLECTIONS.has(collectionName)) {
    throw new Error(`Access to collection "${collectionName}" is forbidden`);
  }

  // --- Sanitise all inputs ---
  const safeFilter = sanitizeFilter(JSON.parse(JSON.stringify(filter)));
  const safeProjection = sanitizeProjection(projection);
  const safeSort = sanitizeSort(sort);

  // --- Pagination guards ---
  const safeLimit = Math.max(1, Math.min(Number(limit) || 50, 500));
  const safeSkip = Math.max(0, Number(skip) || 0);

  const collection = db.collection(collectionName);

  const [data, total] = await Promise.all([
    collection
      .find(safeFilter)
      .project(safeProjection)
      .sort(safeSort)
      .skip(safeSkip)
      .limit(safeLimit)
      .toArray(),
    collection.countDocuments(safeFilter),
  ]);

  return {
    data,
    total,
    limit: safeLimit,
    skip: safeSkip,
  };
}

